    def test_day(self):
        self.doit('daily')

    def test_daily(self):
        self.doit('day')

    def test_monthly(self):
        self.doit('monthly')

    def test_month(self):
        self.doit('month')

    def test_yearly(self):
        self.doit('yearly')

    def test_year(self):
        self.doit('year')

    def doit(self,which):
        g = DateGroup.createGroup(which,self.entries_)
        for index,d in enumerate(g.iterator()):
            result = []
            for i in d:
                result.append(str(i[0]))
            s = '(%s)' % ','.join(result)
            if s != self.output_[which][index]:
                raise ValueError('mismatch: %s %s',s,self.output_[which][index])

    def printit(self,which):
        g = DateGroup.createGroup(which,self.entries_)
        for index,d in enumerate(g.iterator()):
            result = []
            for i in d:
                result.append(str(i[0]))
            s = '(%s),' % ','.join(result)
            print(s)
        

